import React, { Component } from "react";
import Fade from "react-reveal";

let id = 0;
class Portfolio extends Component {
  render() {
    if (!this.props.data) return null;

    const projects = this.props.data.projects.map(function (project) {
      return (
        <div key={id++} className="columns portfolio-item">
          <div className="project-card">
            <h5 className="project-title">{project.title}</h5>
            <p className="project-category">{project.category}</p>
            {project.url && project.url !== "https://github.com/erictang0220" && (
              <a href={project.url} target="_blank" rel="noopener noreferrer" className="project-link">
                View Project
              </a>
            )}
            {(!project.url || project.url === "https://github.com/erictang0220") && (
              <a href="https://github.com/erictang0220" target="_blank" rel="noopener noreferrer" className="project-link">
                GitHub
              </a>
            )}
          </div>
        </div>
      );
    });

    return (
      <section id="portfolio">
        <Fade left duration={1000} distance="40px">
          <div className="row">
            <div className="twelve columns collapsed">
              <h1>Check Out Some of My Works.</h1>
              <div
                id="portfolio-wrapper"
                className="bgrid-quarters s-bgrid-thirds cf"
              >
                {projects}
              </div>
            </div>
          </div>
        </Fade>
      </section>
    );
  }
}

export default Portfolio;
